    20|export function getRemovedImages(
    21|  oldImages: EquipmentImage[],
    22|  newImages: EquipmentImage[]
    23|): string[] {
    24|  const newUrls = new Set(
    25|    newImages.map(img => (typeof img === 'string' ? img : img.url))
    26|  );
    27|  return oldImages
    28|    .filter((img): img is CloudinaryImage => {
    29|      if (typeof img === 'string') return false;
    30|      if (!img.publicId) return false;
    31|      return !newUrls.has(img.url);
    32|    })
    33|    .map(img => img.publicId);
